var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"네가 날 불러들이다니. 인간치고는 속셈을 알 수 없는 놈이로구나.","JPN":"我を呼び出すとは、人間のくせに魂胆が見えぬやつだな。","ENG":"You called me here? I don’t really understand you, human.","TWN":"竟然敢把我找來，真猜不透你在想什麼。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"인간들은 날 가둘 수 있다고 착각한단다. 하지만 영생을 향한 갈증이 세상에 남아있는 한 나는 결국 인간의 욕망에 의해 깨어나게 되어있지.","JPN":"人間は我を封じ込められると勘違いしている。しかし、永生への渇きがこの世に残っている限り、結局我は人間の欲望によって目を覚めるようになっている。","ENG":"You humans believe that you can seal me. But so long as you crave for eternal life, you will eventually wake me up again.","TWN":"人們誤以爲可以將我囚禁起來。但只世界上還有對於永生的追求，我還是會因為人類的慾望而甦醒。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"하지만, 넌 지금껏 단 한 번도 나에게 영생을 요구하지 않았다.","JPN":"しかし、お前はこれまで我に一度も永生を求めてこなかった。","ENG":"But you never asked me for eternal life.","TWN":"不過你從未向我求過永生。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"아주 불쾌하더구나.","JPN":"誠に不快極まりないことだ。","ENG":"That is very unpleasant.","TWN":"我不是很開心。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"내 꼬리에 휘감기면 꼼짝도 못하고 부러질 연약한 인간 주제에…","JPN":"我の尻尾に巻かれたならば、なすすべもなく折れてしまいそうな軟弱な人間の分際で……","ENG":"I can easily crush you with my tail, you fragile human.","TWN":"不過就是個人類，只要被我的尾巴纏住，就只能等著被折斷…"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"영생을 부탁하긴커녕 건방지게 날 연민하듯이 쳐다보다니.","JPN":"永生を願うどころか、生意気にも我に憐憫の眼差しを向けるとは。","ENG":"Yet you look at me sympathetically, instead of begging me for immortality.","TWN":"結果你不但沒有向我求永生，竟然還敢用那種憐憫的眼神看著我。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"후훗, 걱정 마라. 그렇다고 잡아먹진 않을 테니까.","JPN":"フフッ、案ずるな。だからといって取って食うことはせぬ。","ENG":"Hah, don’t worry. I won’t eat you.","TWN":"呵呵，放心，我不會因為這樣就吃掉你。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"다른 인간과는 다르게, 너에겐 복수하고 싶은 기분이 들지 않아.","JPN":"他の人間とは違い、お前には復讐したい気が起きぬのだ。","ENG":"Unlike other humans, I don’t feel like I should take my revenge on you.","TWN":"你和別人不同，我沒有想對你報仇的意思。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"넌 아직 좀 더 살려두고 싶구나.","JPN":"お前はもう少し生かしておきたい。","ENG":"I might keep you around me a bit longer.","TWN":"甚至想讓你再活久一點。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"너 같이 인간의 가장 어두운 면과 가장 밝은 면을 모두 가진 영혼은 처음이야.","JPN":"お前のように人間の最も暗い面と最も明るい面、両方を兼ね備えた魂は初めてだ。","ENG":"I’ve never seen a soul like yours, having both the brightest and the darkest sides of human nature.","TWN":"我還是第一次遇到像你這種人，靈魂裡同時有人類最黑暗與最光明的一面。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"분명 그 영혼이 무르익었을 땐 아주 탐스러운 빛깔을 내겠지.","JPN":"きっとその魂が熟した頃には、とても美味そうな色を放つだろう。","ENG":"I’m sure your soul will ripen delightfully when the time comes.","TWN":"當靈魂成熟時，肯定會發出誘人的光芒。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"그렇게 되기 전까진, 난 네가 원하는 무엇이든 내어줄 생각이란다.","JPN":"そうなるまでは、我はお前が望むものを何でも差し出してやるつもりだ。","ENG":"Until then, I shall give you anything you ask for.","TWN":"在那之前，你想要什麼我都會給你。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"자, 살아있는 동안 힘껏 발버둥치면서 네 영혼의 광채로 날 취하게 해보렴.","JPN":"さあ、生きている間思う存分あがき、お前の魂の輝きで我を酔わせてみなさい。","ENG":"Now, struggle while you live, and shower me with the radiance of your soul.","TWN":"來吧，在活著的時候拼命掙扎，用你靈魂的光芒使我陶醉吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};